/**
 * Sync CHANGELOG.md entries into readme.txt for WordPress.org.
 *
 * Reads the latest version block from CHANGELOG.md (generated by Release Please)
 * and inserts it into the readme.txt `== Changelog ==` section, converting
 * Markdown formatting to WordPress readme format.
 *
 * Run manually or via the sync-changelog GitHub Actions workflow on release PRs.
 *
 * @package Segmentflow_Connect
 */

import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const rootDir = join(__dirname, "..");

const changelogPath = join(rootDir, "CHANGELOG.md");
const readmePath = join(rootDir, "readme.txt");

if (!existsSync(changelogPath)) {
  console.log("No CHANGELOG.md found — nothing to sync.");
  process.exit(0);
}

const changelog = readFileSync(changelogPath, "utf-8");
const readme = readFileSync(readmePath, "utf-8");

/**
 * Extract all version blocks from the CHANGELOG.md.
 *
 * Each block starts with `## [X.Y.Z]` or `## X.Y.Z` and runs until the next
 * `## ` heading or end of file.
 */
const versionBlockRegex = /^## \[?(\d+\.\d+\.\d+)\]?.*?\n([\s\S]*?)(?=^## |\Z)/gm;
const blocks = [];
let match;

while ((match = versionBlockRegex.exec(changelog)) !== null) {
  const version = match[1];
  const body = match[2].trim();
  blocks.push({ version, body });
}

if (blocks.length === 0) {
  console.log("No version blocks found in CHANGELOG.md — nothing to sync.");
  process.exit(0);
}

/**
 * Convert a single CHANGELOG.md version block to WordPress readme.txt format.
 *
 * Input (Markdown):
 *   ### Features
 *   * Added new dashboard ([#12](https://...))
 *   ### Bug Fixes
 *   * Fixed crash on load ([#15](https://...))
 *
 * Output (WP readme):
 *   = 1.2.0 =
 *   * Added new dashboard
 *   * Fixed crash on load
 */
function convertBlock({ version, body }) {
  const lines = body.split("\n");
  const entries = [];

  for (const line of lines) {
    // Skip section headers (### Features, ### Bug Fixes, etc.)
    if (line.startsWith("### ")) continue;
    // Skip empty lines
    if (line.trim() === "") continue;

    // Clean up the entry: remove markdown links, PR references, commit hashes
    let entry = line
      // Strip leading `* ` or `- `
      .replace(/^[\s]*[*-]\s*/, "")
      // Convert markdown links [text](url) to just text
      .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
      // Remove trailing PR/commit references like (#123) or (abc1234)
      .replace(/\s*\([a-f0-9]{7,}\)$/g, "")
      .trim();

    if (entry) {
      entries.push(`* ${entry}`);
    }
  }

  if (entries.length === 0) return null;

  return `= ${version} =\n${entries.join("\n")}`;
}

// Convert all blocks
const wpBlocks = blocks.map(convertBlock).filter(Boolean);

if (wpBlocks.length === 0) {
  console.log("No changelog entries to sync.");
  process.exit(0);
}

// Find the `== Changelog ==` section in readme.txt and replace its content
// with the converted blocks, preserving the existing entries that are already there.
const changelogSectionRegex = /(== Changelog ==\n\n?)([\s\S]*?)((?=\n== )|$)/;
const changelogMatch = readme.match(changelogSectionRegex);

if (!changelogMatch) {
  console.error("Could not find `== Changelog ==` section in readme.txt");
  process.exit(1);
}

const existingChangelog = changelogMatch[2].trim();

// Parse existing versions from readme.txt to avoid duplicates
const existingVersions = new Set();
const existingVersionRegex = /^= (\d+\.\d+\.\d+) =$/gm;
let existingMatch;
while ((existingMatch = existingVersionRegex.exec(existingChangelog)) !== null) {
  existingVersions.add(existingMatch[1]);
}

// Only add blocks for versions not already in readme.txt
const newBlocks = wpBlocks.filter((block) => {
  const versionMatch = block.match(/^= (\d+\.\d+\.\d+) =/);
  return versionMatch && !existingVersions.has(versionMatch[1]);
});

if (newBlocks.length === 0) {
  console.log("All changelog versions already present in readme.txt — nothing to sync.");
  process.exit(0);
}

// Prepend new blocks before existing content
const updatedChangelog = newBlocks.join("\n\n") + "\n\n" + existingChangelog;
const updatedReadme = readme.replace(changelogSectionRegex, `$1${updatedChangelog}\n\n$3`);

writeFileSync(readmePath, updatedReadme);
console.log(
  `Synced ${newBlocks.length} new version(s) to readme.txt: ${newBlocks.map((b) => b.match(/= (.+?) =/)[1]).join(", ")}`,
);
